import{z as t}from"zod";export const StoryStateLanguageSchema=t.enum(["zh","en"]),StateManifestSchema=t.object({schemaVersion:t.literal(2),language:StoryStateLanguageSchema,lastAppliedChapter:t.number().int().min(0),projectionVersion:t.number().int().min(1),migrationWarnings:t.array(t.string()).default([])}),ThreadStatusSchema=t.enum(["open","progressing","deferred","resolved"]),ThreadPayoffTimingSchema=t.enum(["immediate","near-term","mid-arc","slow-burn","endgame"]),PlotThreadSchema=t.object({hookId:t.string().min(1),startChapter:t.number().int().min(0),type:t.string().min(1),status:ThreadStatusSchema,lastAdvancedChapter:t.number().int().min(0),expectedPayoff:t.string().default(""),payoffTiming:ThreadPayoffTimingSchema.optional(),notes:t.string().default(""),dependsOn:t.array(t.string().min(1)).optional(),paysOffInArc:t.string().optional(),coreHook:t.boolean().optional(),halfLifeChapters:t.number().int().positive().optional(),advancedCount:t.number().int().min(0).optional(),promoted:t.boolean().optional()}),PlotThreadsStateSchema=t.object({hooks:t.array(PlotThreadSchema).default([])}),ChapterSummaryRowSchema=t.object({chapter:t.number().int().min(1),title:t.string().min(1),characters:t.string().default(""),events:t.string().default(""),stateChanges:t.string().default(""),hookActivity:t.string().default(""),mood:t.string().default(""),chapterType:t.string().default("")}),ChapterSummariesStateSchema=t.object({rows:t.array(ChapterSummaryRowSchema).default([])}),CurrentStateFactSchema=t.object({subject:t.string().min(1),predicate:t.string().min(1),object:t.string().min(1),validFromChapter:t.number().int().min(0),validUntilChapter:t.number().int().min(0).nullable(),sourceChapter:t.number().int().min(0)}),CurrentStateStateSchema=t.object({chapter:t.number().int().min(0),facts:t.array(CurrentStateFactSchema).default([])}),CurrentStatePatchSchema=t.object({currentLocation:t.string().optional(),protagonistState:t.string().optional(),currentGoal:t.string().optional(),currentConstraint:t.string().optional(),currentAlliances:t.string().optional(),currentConflict:t.string().optional()}),ThreadOpsSchema=t.object({upsert:t.array(PlotThreadSchema).default([]),mention:t.array(t.string().min(1)).default([]),resolve:t.array(t.string().min(1)).default([]),defer:t.array(t.string().min(1)).default([])}),NewThreadCandidateSchema=t.object({type:t.string().min(1),expectedPayoff:t.string().default(""),payoffTiming:ThreadPayoffTimingSchema.optional(),notes:t.string().default("")});const e=t.record(t.string(),t.unknown());export const StoryStateDeltaSchema=t.object({chapter:t.number().int().min(1),currentStatePatch:CurrentStatePatchSchema.optional(),hookOps:ThreadOpsSchema.default({upsert:[],mention:[],resolve:[],defer:[]}),newHookCandidates:t.array(NewThreadCandidateSchema).default([]),chapterSummary:ChapterSummaryRowSchema.optional(),subplotOps:t.array(e).default([]),emotionalArcOps:t.array(e).default([]),characterMatrixOps:t.array(e).default([]),notes:t.array(t.string()).default([])}),StoryStateSnapshotSchema=t.object({manifest:StateManifestSchema,currentState:CurrentStateStateSchema,hooks:PlotThreadsStateSchema,chapterSummaries:ChapterSummariesStateSchema});
